const c = $items('Fetch Full Case')[0]?.json ?? {};
const rawMessages = $items('Fetch Chat Transcript')[0]?.json ?? {};
const messages = Array.isArray(rawMessages) ? rawMessages : (rawMessages.messages || []);
const trimmedTranscript = messages.slice(-40);

const webhookBody = $node['Webhook Trigger']?.json?.body ?? {};

const user_message = {
  case: c,
  transcript: trimmedTranscript,
  closed_by: webhookBody.closed_by ?? null,
  close_reason: webhookBody.close_reason ?? null,
  triage_decision: c.triage_decision ?? null,
  resolution_plan: c.resolution_plan ?? null,
  evidence_bundle: c.evidence_bundle ?? c.information_bundle?.evidence_bundle ?? null,
  proof_uploads: c.proof_uploads ?? c.information_bundle?.proof_uploads ?? [],
  proof_analysis: c.proof_analysis ?? c.information_bundle?.proof_analysis ?? null,
  proof_analysis_status: c.proof_analysis_status ?? c.information_bundle?.proof_analysis_status ?? null,
};

return [{
  case_id: c.id || webhookBody.case_id,
  user_message,
}];

const c = $items('Fetch Full Case')[0]?.json ?? {};
const webhookBody = $node['Webhook Trigger']?.json?.body ?? {};

const coerceToString = (v) => {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'object') {
    if (typeof v.text === 'string') return v.text;
    if (typeof v.output === 'string') return v.output;
    if (typeof v.response === 'string') return v.response;
    if (v.response && typeof v.response.text === 'string') return v.response.text;
  }
  return String(v);
};

const asArray = (v, fallback = []) => Array.isArray(v) ? v : fallback;
const asObject = (v, fallback = null) =>
  v && typeof v === 'object' && !Array.isArray(v) ? v : fallback;

let report;
try {
  if ($json && typeof $json === 'object' && $json.intent_classification !== undefined) {
    report = $json;
  } else {
    const text = coerceToString($json);
    report = JSON.parse(text);
  }
} catch (e) {
  report = null;
}

const fallbackEvidenceBundle =
  c.evidence_bundle ??
  c.information_bundle?.evidence_bundle ??
  null;

const fallbackProofUploads =
  c.proof_uploads ??
  c.information_bundle?.proof_uploads ??
  null;

const fallbackTriageDecision = asObject(c.triage_decision, {});
const fallbackResolutionActions = asObject(c.resolution_plan, null);

const hasCoreFields = report &&
  typeof report.intent_classification === 'string' &&
  Array.isArray(report.data_sources_queried) &&
  typeof report.outcome_summary === 'string' &&
  report.outcome_summary.trim().length > 0;

if (!hasCoreFields) {
  report = {
    case_id: c.id || webhookBody.case_id,
    dispute_type: c.dispute_type || 'unknown',
    customer_name: c.customer_name || 'Unknown Customer',
    customer_email: c.customer_email || 'unknown@example.com',
    order_id: c.order_id || '',
    intent_classification: c.dispute_subtype || c.dispute_type || 'unknown',
    data_sources_queried: ['internal'],
    policies_applied: asArray(fallbackTriageDecision?.policies_applied),
    slas_applied: asArray(fallbackTriageDecision?.slas_applied),
    triage_decision: fallbackTriageDecision,
    resolution_path: c.resolution_path || 'unknown',
    approval_outcome: null,
    rejection_reason: c.rejection_reason || null,
    resolution_actions: fallbackResolutionActions,
    evidence_bundle: fallbackEvidenceBundle,
    proof_uploads: fallbackProofUploads,
    outcome_summary: `Case ${c.id || webhookBody.case_id} closed with status ${c.status || 'closed'}.`,
    close_reason: webhookBody.close_reason || c.close_reason || 'resolved',
  };
} else {
  report = {
    case_id: c.id || webhookBody.case_id,
    dispute_type: report.dispute_type ?? c.dispute_type ?? 'unknown',
    customer_name: report.customer_name ?? c.customer_name ?? 'Unknown Customer',
    customer_email: report.customer_email ?? c.customer_email ?? 'unknown@example.com',
    order_id: report.order_id ?? c.order_id ?? '',
    intent_classification: report.intent_classification,
    data_sources_queried: asArray(report.data_sources_queried, ['internal']),
    policies_applied: asArray(report.policies_applied, asArray(fallbackTriageDecision?.policies_applied)),
    slas_applied: asArray(report.slas_applied, asArray(fallbackTriageDecision?.slas_applied)),
    triage_decision: asObject(report.triage_decision, fallbackTriageDecision),
    resolution_path: report.resolution_path ?? c.resolution_path ?? 'unknown',
    approval_outcome: report.approval_outcome ?? null,
    rejection_reason: report.rejection_reason ?? c.rejection_reason ?? null,
    resolution_actions: asObject(report.resolution_actions, fallbackResolutionActions),
    evidence_bundle: asObject(report.evidence_bundle, fallbackEvidenceBundle),
    proof_uploads: Array.isArray(report.proof_uploads) ? report.proof_uploads : fallbackProofUploads,
    outcome_summary: report.outcome_summary,
    close_reason: report.close_reason ?? webhookBody.close_reason ?? c.close_reason ?? 'resolved',
  };
}

return [{
  case_id: c.id || webhookBody.case_id,
  closed_by: webhookBody.closed_by || null,
  close_reason: webhookBody.close_reason || null,
  report,
}];
